  Future<String> _getPresignedUrl() async {
    final url = Uri.parse('https://s3.$region.amazonaws.com/$bucketName');
    final now = DateTime.now();
    final date = now.toUtc().toIso8601String().split('T')[0];
    final dateTime = now.toUtc().toIso8601String().replaceAll(RegExp(r'[-:T]'), '');
    
    final policy = {
      'expiration': '${date}T23:59:59Z',
      'conditions': [
        {'bucket': bucketName},
        {'key': '${DateTime.now().millisecondsSinceEpoch}.jpg'},
        {'acl': 'public-read'},
        {'content-type': 'image/jpeg'},
        {'x-amz-meta-uuid': Uuid().v4()},
        {'x-amz-server-side-encryption': 'AES256'},
        ['content-length-range', 0, 10485760],
      ]
    };

    final policyString = Uri.encodeComponent(
      const JsonEncoder.withIndent(' ').convert(policy)
    );

    final signature = _calculateSignature(
      policyString,
      awsSecretKey,
      date,
      region,
      bucketName
    );

    final response = await http.post(
      url,
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: {
        'key': '${DateTime.now().millisecondsSinceEpoch}.jpg',
        'acl': 'public-read',
        'content-type': 'image/jpeg',
        'x-amz-meta-uuid': Uuid().v4(),
        'x-amz-server-side-encryption': 'AES256',
        'policy': policyString,
        'x-amz-signature': signature,
        'x-amz-credential': '$awsAccessKey/$date/$region/s3/aws4_request',
        'x-amz-date': dateTime,
      },
    );

    return response.headers['location'] ?? '';
  }

