  String _calculateSignature(
    String policy,
    String secretKey,
    String date,
    String region,
    String service,
  ) {
    final kDate = _hmacSHA256('AWS4$secretKey', date);
    final kRegion = _hmacSHA256(kDate, region);
    final kService = _hmacSHA256(kRegion, service);
    final kSigning = _hmacSHA256(kService, 'aws4_request');
    
    final signature = _hmacSHA256(kSigning, policy);
    return signature;
