  String _hmacSHA256(String key, String data) {
    final keyBytes = Uint8List.fromList(key.codeUnits);
    final dataBytes = Uint8List.fromList(data.codeUnits);
    final hmac = Hmac(sha256, keyBytes);
    final digest = hmac.convert(dataBytes);
    return digest.toString().substring(2);
  }

